import{_ as a,o as r,c as i,ae as t}from"./chunks/framework.CyZiF_rV.js";const g=JSON.parse('{"title":"KSeF API 2.0 – Обзор ключевых изменений","description":"","frontmatter":{},"headers":[],"relativePath":"ru/przeglad-kluczowych-zmian-ksef-api-2-0.md","filePath":"ru/przeglad-kluczowych-zmian-ksef-api-2-0.md"}'),l={name:"ru/przeglad-kluczowych-zmian-ksef-api-2-0.md"};function p(n,e,o,s,h,u){return r(),i("div",null,[...e[0]||(e[0]=[t('<blockquote><p><strong>Translation.</strong> Original: <a href="https://github.com/CIRFMF/ksef-docs/blob/main/przeglad-kluczowych-zmian-ksef-api-2-0.md" target="_blank" rel="noreferrer">przeglad-kluczowych-zmian-ksef-api-2-0.md</a></p></blockquote><h1 id="ksef-api-2-0-–-обзор-ключевых-изменении" tabindex="-1">KSeF API 2.0 – Обзор ключевых изменений <a class="header-anchor" href="#ksef-api-2-0-–-обзор-ключевых-изменении" aria-label="Permalink to &quot;KSeF API 2.0 – Обзор ключевых изменений&quot;">​</a></h1><p>09.06.2025</p><h1 id="введение" tabindex="-1">Введение <a class="header-anchor" href="#введение" aria-label="Permalink to &quot;Введение&quot;">​</a></h1><p>Данный документ предназначен для технических команд и программистов, имеющих опыт работы с версией 1.0 API KSeF. Он содержит обзор наиболее важных изменений, внесенных в версию 2.0, с обсуждением новых возможностей и практических улучшений в интеграции.</p><p>Цель документа:</p><ul><li>Указать основные различия относительно версии 1.0</li><li>Представить преимущества миграции на версию 2.0</li><li>Облегчить подготовку интеграции к требованиям системы, внедряемым 1 февраля 2026 г.</li></ul><hr><h2 id="документация-и-инструменты-поддерживающие-интеграцию-с-ksef-api-2-0" tabindex="-1">Документация и инструменты, поддерживающие интеграцию с KSeF API 2.0 <a class="header-anchor" href="#документация-и-инструменты-поддерживающие-интеграцию-с-ksef-api-2-0" aria-label="Permalink to &quot;Документация и инструменты, поддерживающие интеграцию с KSeF API 2.0&quot;">​</a></h2><p>Чтобы облегчить переход на новую версию API и обеспечить правильную реализацию, предоставлен набор официальных материалов и инструментов, поддерживающих интеграторов:</p><p><strong>Техническая документация (OpenAPI)</strong></p><p>Версия 2.0 API KSeF была описана в стандарте OpenAPI, что позволяет как легко просматривать документацию программистами, так и автоматически генерировать интеграционный код.</p><ul><li><p><strong>Документация</strong> (интерактивная онлайн-версия):<br> Браузерный интерфейс в виде веб-страницы, представляющий описания методов API, модели данных, параметры и примеры использования. Предназначен для программистов и аналитиков интеграции: [<a href="https://api-test.ksef.mf.gov.pl/docs/v2/index.html" target="_blank" rel="noreferrer">link</a>].</p></li><li><p><strong>Спецификация</strong> (файл JSON OpenAPI):<br> Исходный файл спецификации OpenAPI в формате JSON, предназначенный для использования в инструментах автоматизации интеграции (например, генераторы кода, валидаторы контрактов API): [<a href="https://api-test.ksef.mf.gov.pl/docs/v2/openapi.json" target="_blank" rel="noreferrer">link</a>].</p></li></ul><p><strong>Официальная интеграционная библиотека KSeF 2.0 Client (open source)</strong></p><p>Публичная библиотека, предоставляемая на условиях open source, разрабатываемая параллельно с новыми версиями API и поддерживаемая в полном соответствии со спецификацией. Является рекомендуемым интеграционным инструментом, позволяющим отслеживать изменения в текущем режиме и снижать риск несовместимости с актуальными выпусками системы.</p><ul><li><p><strong>C#:</strong> [<a href="https://github.com/CIRFMF/ksef-client-csharp" target="_blank" rel="noreferrer">link</a>]</p></li><li><p><strong>Java:</strong> [<a href="https://github.com/CIRFMF/ksef-client-java" target="_blank" rel="noreferrer">link</a>]</p></li></ul><p><strong>Опубликованные пакеты</strong></p><p>Библиотека KSeF 2.0 Client будет доступна в официальных репозиториях пакетов для наиболее популярных языков программирования. Для платформы .NET она будет опубликована как пакет NuGet, а для среды Java – как артефакт Maven Central. Публикация в этих репозиториях позволит легко включить библиотеку в проекты и автоматически отслеживать обновления, совместимые с последующими версиями API.</p><p><strong>Пошаговое руководство</strong></p><ul><li><strong>Руководство по интеграции / tutorial:</strong><br> Практические инструкции шаг за шагом с фрагментами кода, иллюстрирующими способ использования ключевых endpoints системы. <br>[<a href="https://github.com/CIRFMF/ksef-docs" target="_blank" rel="noreferrer">link</a>]</li></ul><h1 id="ключевые-изменения-в-api-2-0" tabindex="-1">Ключевые изменения в API 2.0 <a class="header-anchor" href="#ключевые-изменения-в-api-2-0" aria-label="Permalink to &quot;Ключевые изменения в API 2.0&quot;">​</a></h1><h2 id="новая-модель-аутентификации-на-основе-jwt" tabindex="-1">Новая модель аутентификации на основе JWT <a class="header-anchor" href="#новая-модель-аутентификации-на-основе-jwt" aria-label="Permalink to &quot;Новая модель аутентификации на основе JWT&quot;">​</a></h2><p>В версии 1.0 аутентификация была тесно связана с открытием интерактивной сессии, что вносило множество ограничений и усложняло интеграцию.</p><p>В версии 2.0:</p><ul><li><p>Аутентификация была <strong>выделена как отдельный процесс</strong>, независимый от инициализации сессии.</p></li><li><p>Введены <strong>стандартные токены JWT</strong>, которые используются для авторизации всех защищенных операций.</p></li></ul><p>Преимущества:</p><ul><li>соответствие рыночным практикам,</li><li>возможность многократного использования токена для создания множества сессий,</li><li><strong>поддержка обновления и аннулирования токенов</strong>.</li></ul><p>Подробности процесса аутентификации: [<a href="https://github.com/CIRFMF/ksef-docs/blob/main/uwierzytelnianie.md" target="_blank" rel="noreferrer">link</a>]</p><h2 id="унифицированныи-процесс-инициализации-для-пакетнои-и-интерактивнои-сессии" tabindex="-1">Унифицированный процесс инициализации для пакетной и интерактивной сессии <a class="header-anchor" href="#унифицированныи-процесс-инициализации-для-пакетнои-и-интерактивнои-сессии" aria-label="Permalink to &quot;Унифицированный процесс инициализации для пакетной и интерактивной сессии&quot;">​</a></h2><p>В API 2.0 процесс открытия сессии был унифицирован и сделан независимым от режима работы. После получения аутентифицирующего токена можно открыть как интерактивную сессию: POST /sessions/online, так и пакетную: POST /sessions/batch.</p><p>В обоих случаях передается простой JSON, содержащий:</p><ul><li><p>код формы (formCode),</p></li><li><p>зашифрованный ключ AES для шифрования данных счетов-фактур (encryptionKey).</p></li></ul><p>В случае пакетной отправки также передается список частичных файлов с метаданными, входящими в состав пакета.</p><p>Подробности и примеры использования:</p><ul><li>интерактивная отправка [<a href="https://github.com/CIRFMF/ksef-docs/blob/main/sesja-interaktywna.md" target="_blank" rel="noreferrer">link</a>]</li><li>пакетная отправка [<a href="https://github.com/CIRFMF/ksef-docs/blob/main/sesja-wsadowa.md" target="_blank" rel="noreferrer">link</a>]</li></ul><h2 id="обязательное-шифрование-всех-счетов-фактур" tabindex="-1">Обязательное шифрование всех счетов-фактур <a class="header-anchor" href="#обязательное-шифрование-всех-счетов-фактур" aria-label="Permalink to &quot;Обязательное шифрование всех счетов-фактур&quot;">​</a></h2><p>В версии 1.0 шифрование счетов-фактур было обязательным только в пакетном режиме. В интерактивном режиме возможность шифрования существовала, но была опциональной.</p><p>В версии 2.0 шифрование всех счетов-фактур – как в пакетном, так и в интерактивном режиме – <strong>является обязательным</strong>.</p><p>Каждый счет-фактура или пакет счетов-фактур должен быть зашифрован локально клиентом с помощью <strong>ключа AES</strong>, который:</p><ul><li><p>генерируется индивидуально для каждой сессии,</p></li><li><p>передается в систему при открытии сессии (encryptionKey).</p></li></ul><h2 id="асимметричное-шифрование" tabindex="-1">Асимметричное шифрование <a class="header-anchor" href="#асимметричное-шифрование" aria-label="Permalink to &quot;Асимметричное шифрование&quot;">​</a></h2><p>В версии 2.0 введено <code>RSA-OAEP</code> с <code>SHA-256</code> и <code>MGF1-SHA256</code>. Шифрование токенов KSeF реализуется отдельным ключом, отличным от шифрования симметричного ключа, используемого для счетов-фактур.</p><p>Актуальные <strong>сертификаты открытых ключей</strong> возвращаются публичным endpoint: GET <code>/security/public-key-certificates</code></p><h2 id="согласованность-и-новая-конвенция-именования-в-api-2-0" tabindex="-1">Согласованность и новая конвенция именования в API 2.0 <a class="header-anchor" href="#согласованность-и-новая-конвенция-именования-в-api-2-0" aria-label="Permalink to &quot;Согласованность и новая конвенция именования в API 2.0&quot;">​</a></h2><p>Одним из ключевых изменений в KSeF API 2.0 является унификация и упрощение конвенции именования ресурсов, параметров и моделей json. В версии 1.0 API содержал ряд несогласованностей и избыточной сложности, возникших в результате эволюции системы.</p><p>В версии 2.0:</p><ul><li><p><strong>Endpoints</strong> получили читаемое, REST-овое именование (например, sessions/online, auth/token, permissions/entities/grants).</p></li><li><p><strong>Названия операций</strong> были упрощены и отражают фактическое действие (например, grant, revoke, refresh).</p></li><li><p>Упорядочена структура <strong>заголовков, параметров и форматов данных</strong>, чтобы она была согласованной и соответствовала лучшим практикам проектирования REST API.</p></li><li><p><strong>Структуры данных</strong> являются плоскими и ясными – типы идентификаторов и разрешений имеют явно определенные типы enum (Nip, Pesel, Fingerprint), без необходимости анализа подтипов.</p></li></ul><p>Изменения в версии 2.0 включают также обновление названий и структур данных. Хотя полная карта этих изменений не представлена в данном документе, она доступна в документации OpenAPI v2 и в примерах кода в официальном репозитории GitHub.</p><p>Следует подчеркнуть, что изменения не носят кардинального характера – <strong>не влияют</strong> на общую логику работы системы KSeF, а только упорядочивают и упрощают именование и структуры, делая API более прозрачным и интуитивным в использовании.</p><p>Миграция на версию 2.0 должна рассматриваться как изменение интеграционного контракта и требует адаптации реализации со стороны внешних систем. Рекомендуется использование официальной интеграционной библиотеки <strong>KSeF 2.0 Client</strong>, разрабатываемой и поддерживаемой командой, ответственной за API. Эта библиотека реализует все доступные endpoints и модели данных, что значительно облегчает процесс миграции и обеспечивает стабильную поддержку также в будущих версиях системы.</p><h2 id="новыи-модуль-для-управления-внутренними-сертификатами" tabindex="-1">Новый модуль для управления внутренними сертификатами <a class="header-anchor" href="#новыи-модуль-для-управления-внутренними-сертификатами" aria-label="Permalink to &quot;Новый модуль для управления внутренними сертификатами&quot;">​</a></h2><p>В рамках версии KSeF API 2.0 введены механизмы, позволяющие выдавать и управлять внутренними <strong>сертификатами KSeF</strong> [ссылка на документацию]. Сертификаты будут позволять аутентификацию в KSeF и необходимы для выставления счета-фактуры в офлайн режиме [ссылка на документацию].</p><p>Субъекты, которые успешно пройдут процесс аутентификации, смогут:</p><ul><li><p>подать заявку на выдачу внутреннего сертификата KSeF, содержащего выбранные атрибуты из сертификата подписи, используемого при аутентификации,</p></li><li><p>загрузить выданный сертификат в цифровом виде,</p></li><li><p>проверить статус поданной заявки на выдачу сертификата,</p></li><li><p>загрузить список метаданных выданных сертификатов,</p></li><li><p>проверить действующий лимит количества сертификатов.</p></li></ul><h2 id="улучшение-процесса-пакетнои-отправки" tabindex="-1">Улучшение процесса пакетной отправки <a class="header-anchor" href="#улучшение-процесса-пакетнои-отправки" aria-label="Permalink to &quot;Улучшение процесса пакетной отправки&quot;">​</a></h2><p>В версии KSeF API 2.0 введено существенное усовершенствование в области обработки пакетных сессий. Предыдущее решение, доступное в API 1.0, было неэффективным – в случае, когда хотя бы один счет-фактура в пакете содержал ошибку, отклонялась вся отправка. Такой подход эффективно ограничивал использование пакетного режима интеграторами и вызывал значительные операционные затруднения.</p><p>В новом решении при отправке пакета документов:</p><ul><li><p>каждый счет-фактура обрабатывается независимо,</p></li><li><p>возможные ошибки влияют только на конкретные счета-фактуры, а не на всю отправку,</p></li><li><p>количество ошибочных счетов-фактур возвращается для статуса сессии,</p></li><li><p>доступен специализированный endpoint, позволяющий загрузить детальный статус неправильно обработанных счетов-фактур вместе с информацией о возможной ошибке.</p></li></ul><p>Это изменение значительно повышает надежность и эффективность пакетного режима и основывается на той же модели отправки пакетов без риска потери всего пакета из-за отдельных ошибок.</p><h2 id="верификация-дубликатов-счетов-фактур" tabindex="-1">Верификация дубликатов счетов-фактур <a class="header-anchor" href="#верификация-дубликатов-счетов-фактур" aria-label="Permalink to &quot;Верификация дубликатов счетов-фактур&quot;">​</a></h2><p>Изменен способ обнаружения дубликатов – теперь проверяются бизнес-данные счета-фактуры (Podmiot1:NIP, RodzajFaktury, P_2), а не хеш файла. Подробности – <a href="./faktury/weryfikacja-faktury.html">Верификация дубликатов</a>.</p><h2 id="изменение-в-модуле-разрешении" tabindex="-1">Изменение в модуле Разрешений <a class="header-anchor" href="#изменение-в-модуле-разрешении" aria-label="Permalink to &quot;Изменение в модуле Разрешений&quot;">​</a></h2><p>Изменения в модуле разрешений связаны с изменением некоторых аспектов логики их функционирования в KSeF 2.0.</p><p>В ответ на поступающие замечания, в версии 2.0 системы введен механизм предоставления разрешений косвенным способом, который заменяет действующий до сих пор принцип наследования разрешений на просмотр и выставление счетов-фактур. Новый интерфейс позволяет разделить просмотр счетов-фактур клиента (партнера) и возможность выставления счетов-фактур от его имени от просмотра счетов-фактур и выставления собственных счетов-фактур субъекта (например, бухгалтерского бюро).</p><p>Механизм заключается в предоставлении субъекту клиентом разрешения на просмотр или выставление счетов-фактур с включенной специальной опцией, разрешающей дальнейшую передачу этого разрешения уполномоченным субъектом. После получения такого разрешения субъект может предоставить его, например, своим сотрудникам. После выполнения этих действий данные сотрудники будут иметь возможность обслуживать указанного клиента в объеме, определенном предоставленными разрешениями.</p><p>Также возможно предоставление субъектом так называемых общих разрешений, которые позволяют уполномоченному таким образом сотруднику обслуживать всех клиентов субъекта – конечно, в таком объеме, в каком эти клиенты уполномочили данный субъект и с учетом объема разрешений сотрудника (на просмотр и/или выставление счетов-фактур).</p><p>Благодаря такому механизму предоставление и функционирование разрешений на просмотр и выставление счетов-фактур в рамках самого субъекта не связаны с разрешениями на обслуживание счетов-фактур клиентов. Это дает субъектам лучшие возможности профилирования разрешений сотрудников, чем ранее функционировавший в KSeF механизм наследования разрешений. Он заключался в предоставлении разрешений сотрудникам на просмотр и выставление счетов-фактур в рамках субъекта, а если субъект обладал соответствующими разрешениями от клиентов, то эти разрешения автоматически переходили к сотрудникам (наследовались). В результате – сотрудник мог обслуживать клиентов только тогда, когда одновременно имел право на просмотр и/или выставление счетов-фактур субъекта. А это во многих случаях было избыточным разрешением, что могло вызывать проблемы в организациях.</p><p>Кроме того, в системе введен новый тип разрешения и новые возможности входа в систему, что позволяет обслуживать самовыставление счетов-фактур субъектами ЕС. Возможен теперь вход в систему в контексте, определенном польским субъектом (идентифицируемым по NIP) и субъектом из страны ЕС, идентифицируемым номером VAT страны ЕС. В таком определенном контексте возможно выставление аутентифицированными представителями указанного субъекта ЕС счетов-фактур в режиме самовыставления от имени указанного польского субъекта.</p><p>В рамках определения API все разрешения были упорядочены в логические группы, соответствующие отдельным функциональным областям системы.</p><h2 id="лимиты-вызовов-api-rate-limiting" tabindex="-1">Лимиты вызовов API (rate limiting) <a class="header-anchor" href="#лимиты-вызовов-api-rate-limiting" aria-label="Permalink to &quot;Лимиты вызовов API (rate limiting)&quot;">​</a></h2><p>В версии KSeF API 2.0 введен точный и предсказуемый механизм ограничения количества вызовов (rate limits), который заменяет существующие решения, известные из версии 1.0. Каждый endpoint в системе охвачен лимитом количества запросов в заданных временных интервалах: в секунду, минуту, час.</p><p>Диапазоны и значения лимитов:</p><ul><li>публично предоставляются: <a href="./limity/limity-api.html">лимиты API</a>,</li><li>дифференцированы в зависимости от среды (тестовая среда имеет менее ограничительные лимиты, чем продуктивная),</li><li>адаптированы к характеру операций: <ul><li>для защищенных endpoints – лимиты применяются на контекст и IP-адрес,</li><li>для открытых endpoints – лимиты применяются на IP-адрес.</li></ul></li></ul><p>Новая модель лимитов была разработана так, чтобы не ограничивать типичное тестирование приложений, интегрирующихся с системой. Это решение обеспечивает большую прозрачность, предсказуемость и лучшую устойчивость системы как в тестовых, так и в продуктивных средах.</p><h2 id="вспомогательныи-api-для-генерации-тестовых-данных-тестовая-среда" tabindex="-1">Вспомогательный API для генерации тестовых данных (тестовая среда) <a class="header-anchor" href="#вспомогательныи-api-для-генерации-тестовых-данных-тестовая-среда" aria-label="Permalink to &quot;Вспомогательный API для генерации тестовых данных (тестовая среда)&quot;">​</a></h2><p>В тестовой среде KSeF API 2.0 будет предоставлен специализированный <strong>вспомогательный API для генерации тестовых данных</strong>, позволяющий быстро создавать фирмы, организационные структуры и контексты, необходимые для проведения интеграционных тестов.</p><p>Благодаря этому решению станет возможным, в частности:</p><ul><li><p><strong>симуляция создания нового хозяйствующего субъекта</strong>,</p></li><li><p><strong>симуляция предоставления разрешений ZAW-FA</strong>,</p></li><li><p><strong>создание единиц в рамках структуры JST</strong>,</p></li><li><p>создание налоговых <strong>групп VAT</strong> (GVAT) с связанными субъектами,</p></li><li><p><strong>определение исполнительных органов</strong> <strong>и судебных приставов</strong>.</p></li></ul><p>Стандартно процесс регистрации фирм и предоставления разрешений для реальных субъектов в продуктивной среде требует формальных действий (например, посещения налогового органа). В тестовой среде такие данные не существуют. Поэтому <strong>вспомогательный API является необходимым инструментом</strong>, позволяющим интеграторам самостоятельно создавать тестовых субъектов, на которых они могут свободно реализовывать и верифицировать полные сценарии работы своих приложений.</p>',79)])])}const c=a(l,[["render",p]]);export{g as __pageData,c as default};
